# flavor.toml File Content

The provided content is a complete **flavor.toml** configuration file for Yazi (a terminal file manager). Here's the entire file as written:

```toml
# vim:fileencoding=utf-8:foldmethod=marker

# : Manager {{{

[mgr]
cwd = { fg = "#7fbbb3" }

# Hovered
hovered         = { reversed = true }
preview_hovered = { underline = true }

# Find
find_keyword  = { fg = "#dbbc7f", bold = true, italic = true, underline = true }
find_position = { fg = "#d699b6", bg = "reset", bold = true, italic = true }

# Symlink
symlink_target = { italic = true }

# Marker
marker_copied   = { fg = "#a7c080", bg = "#a7c080" }
marker_cut      = { fg = "#e67e80", bg = "#e67e80" }
marker_marked   = { fg = "#7fbbb3", bg = "#7fbbb3" }
marker_selected = { fg = "#dbbc7f", bg = "#dbbc7f" }

# Count
count_copied   = { fg = "#343f44", bg = "#a7c080" }
count_cut      = { fg = "#343f44", bg = "#e67e80" }
count_selected = { fg = "#343f44", bg = "#dbbc7f" }

# Border
border_symbol = "│"
border_style  = { fg = "#4f585e" }

# Highlighting
syntect_theme = ""

# : }}}


# : Tabs {{{

[tabs]
active   = { bg = "#7fbbb3", bold = true }
inactive = { fg = "#7fbbb3", bg = "#4f585e" }

# Separator
sep_inner = { open = "", close = "" }
sep_outer = { open = "", close = "" }

# : }}}


# : Mode {{{

[mode]
normal_main = { fg = "#3d484d", bg = "#a7c080", bold = true }
normal_alt  = { fg = "#7fbbb3", bg = "#4f585e", bold = true }

# Select mode
select_main = { fg = "#3d484d", bg = "#e67e80", bold = true }
select_alt  = { fg = "#7fbbb3", bg = "#4f585e", bold = true }

# Unset mode
unset_main = { fg = "#3d484d", bg = "#7fbbb3", bold = true }
unset_alt  = { fg = "#7fbbb3", bg = "#4f585e", bold = true }

# : }}}


# : Status bar {{{

[status]
overall   = {}
sep_left  = { open = "", close = "" }
sep_right = { open = "", close = "" }

# Permissions
perm_sep   = { fg = "#2d353b" }
perm_type  = { fg = "#a7c080" }
perm_read  = { fg = "#dbbc7f" }
perm_write = { fg = "#e67e80" }
perm_exec  = { fg = "#7fbbb3" }

# Progress
progress_label  = { bold = true }
progress_normal = { fg = "#7fbbb3", bg = "#232a2e" }
progress_error  = { fg = "#e67e80", bg = "#232a2e" }

# : }}}


# : Which {{{

[which]
cols            = 3
mask            = { bg = "#2d353b" }
cand            = { fg = "#7fbbb3" }
rest            = { fg = "#2d353b" }
desc            = { fg = "#d699b6" }
separator       = "  "
separator_style = { fg = "#2d353b" }

# : }}}


# : Confirmation {{{

[confirm]
border     = { fg = "#7fbbb3" }
title      = { fg = "#7fbbb3" }
body       = {}
list       = {}
btn_yes    = { reversed = true }
btn_no     = {}
btn_labels = [ "  [Y]es  ", "  (N)o  " ]

# : }}}


# : Spotter {{{

[spot]
border = { fg = "#7fbbb3" }
title  = { fg = "#7fbbb3" }

# Table
tbl_col  = { fg = "#7fbbb3" }
tbl_cell = { fg = "#dbbc7f", reversed = true }

# : }}}


# : Notification {{{

[notify]
title_info  = { fg = "#a7c080" }
title_warn  = { fg = "#dbbc7f" }
title_error = { fg = "#e67e80" }

# Icons
icon_info  = ""
icon_warn  = ""
icon_error = ""

# : }}}


# : Picker {{{

[pick]
border   = { fg = "#7fbbb3" }
active   = { fg = "#d699b6", bold = true }
inactive = {}

# : }}}


# : Input {{{

[input]
border   = { fg = "#7fbbb3" }
title    = {}
value    = {}
selected = { reversed = true }

# : }}}


# : Completion {{{

[cmp]
border   = { fg = "#7fbbb3" }
active   = { reversed = true }
inactive = {}

# Icons
icon_file    = ""
icon_folder  = ""
icon_command = ""

# : }}}


# : Task manager {{{

[tasks]
border  = { fg = "#7fbbb3" }
title   = {}
hovered = { fg = "#d699b6", underline = true }

# : }}}


# : Help menu {{{

[help]
on      = { fg = "#7fbbb3" }
run     = { fg = "#d699b6" }
desc    = {}
hovered = { reversed = true, bold = true }
footer  = { fg = "#2d353b", bg = "#d3c6aa" }

# : }}}


# : File-specific styles {{{

[filetype]

rules = [
	# Images
	{ mime = "image/*", fg = "#7fbbb3" },

	# Media
	{ mime = "{audio,video}/*", fg = "#d699b6" },

	# Archives
	{ mime = "application/*zip", fg = "#e67e80" },
	{ mime = "application/x-{tar,bzip*,7z-compressed,xz,rar}", fg = "#e67e80" },

	# Documents
	{ mime = "application/{pdf,doc,rtf,vnd.*}", fg = "#7fbbb3" },

	# Virtual file system
	{ mime = "vfs/{absent,stale}", fg = "#4f585e" },

	# Fallback
	{ url = "*", fg = "#83c092" },
	{ url = "*/", fg = "#a7c080" },
	# Legacy (for older yazi versions)
	{ name = "*", fg = "#83c092" },
	{ name = "*/", fg = "#a7c080" }
]

# : }}}
```

This configuration defines a color theme for Yazi featuring earthy, muted tones with teal, orange, and golden accents throughout the interface.

